110→          </Text>
111→          {profile?.username ? (
112→            <Text style={[styles.username, {color: colors.textMuted}]}>
113→              @{profile.username}
114→            </Text>
115→          ) : null}
116→
117→          <View style={styles.badgeRow}>
118→            {profile?.badge_type ? (
119→              <View
120→                style={[
121→                  styles.badgePill,
122→                  {
123→                    backgroundColor:
124→                      profile.badge_type === 'legend'
125→                        ? 'rgba(255,215,0,0.15)'
126→                        : 'rgba(155,89,255,0.15)',
127→                    borderColor:
128→                      profile.badge_type === 'legend'
129→                        ? colors.badgeLegendBorder
130→                        : colors.badgeOGBorder,
131→                  },
132→                ]}>
133→                <Text
134→                  style={[
135→                    styles.badgeText,
136→                    {
137→                      color:
138→                        profile.badge_type === 'legend'
139→                          ? colors.badgeLegendBorder
140→                          : colors.badgeOGBorder,
141→                    },
142→                  ]}>
143→                  {profile.badge_type.toUpperCase()}
144→                </Text>
145→              </View>
146→            ) : null}
147→
148→            {streak != null && streak > 0 ? (
149→              <View style={[styles.streakBadge, {backgroundColor: 'rgba(245,158,11,0.12)'}]}>
150→                <FireIcon size={14} color="#F59E0B" />
151→                <Text style={styles.streakText}>{streak}</Text>
152→              </View>
153→            ) : null}
154→          </View>
155→        </View>
156→
157→        {/* Bio */}
158→        {profile?.bio ? (
159→          <Text style={[styles.bio, {color: colors.textSecondary}]}>
160→            {profile.bio}
161→          </Text>
162→        ) : null}
163→
164→        {/* Action row */}
165→        <View style={styles.actionRow}>
166→          <View style={styles.editBtn}>
167→            <PrimaryButton
168→              label="Edit Profile"
169→              onPress={onEditProfile}
170→              kind="secondary"
171→            />
172→          </View>
173→          <Pressable
174→            style={[styles.shareBtn, {borderColor: colors.borderLight}]}
175→            onPress={onShareProfile}
176→            hitSlop={8}>
177→            <ShareIcon size={18} color={colors.textSecondary} />
178→          </Pressable>
179→        </View>
180→      </View>
181→    </View>
182→  );
