104→const authHeaders = (token?: string): Record<string, string> => {
105→  if (!token) {
106→    return {};
107→  }
108→
109→  return {
110→    Authorization: `Bearer ${token}`,
111→  };
112→};
113→
114→export const mobileApi = {
115→  async getJournals(cursor: string | null, limit = 10, userId?: string): Promise<CursorPage<JournalItem>> {
116→    const params = new URLSearchParams();
117→    params.set('limit', String(limit));
118→    if (cursor) {
119→      params.set('before', cursor);
120→    }
121→    if (userId) {
122→      params.set('userId', userId);
123→    }
124→
125→    return apiRequest<CursorPage<JournalItem>>(`/journals?${params.toString()}`, {
126→      method: 'GET',
127→    });
128→  },
129→
130→  async getJournalById(journalId: string, userId?: string): Promise<{ journal: JournalItem }> {
131→    const params = new URLSearchParams();
132→    if (userId) {
133→      params.set('userId', userId);
134→    }
135→
136→    const suffix = params.toString() ? `?${params.toString()}` : '';
137→    return apiRequest<{ journal: JournalItem }>(`/journal/${encodeURIComponent(journalId)}${suffix}`, {
138→      method: 'GET',
139→    });
140→  },
141→
142→  async searchUsers(query: string, limit = 20): Promise<{ data: UserPreview[]; hasMore: boolean }> {
143→    const params = new URLSearchParams();
144→    params.set('query', query.trim());
145→    params.set('limit', String(limit));
146→
147→    return apiRequest<{ data: UserPreview[]; hasMore: boolean }>(`/users/search?${params.toString()}`, {
148→      method: 'GET',
149→    });
150→  },
151→
152→  async searchJournals(query: string, limit = 20, userId?: string): Promise<{ data: JournalItem[]; hasMore: boolean }> {
153→    const params = new URLSearchParams();
154→    params.set('query', query.trim());
155→    params.set('limit', String(limit));
156→    if (userId) {
157→      params.set('userId', userId);
158→    }
159→
160→    return apiRequest<{ data: JournalItem[]; hasMore: boolean }>(`/journals/search?${params.toString()}`, {
161→      method: 'GET',
162→    });
163→  },
164→
165→  async getNotifications(token: string, cursor: string | null, limit = 20): Promise<CursorPage<NotificationItem>> {
166→    const params = new URLSearchParams();
167→    params.set('limit', String(limit));
168→    if (cursor) {
169→      params.set('before', cursor);
170→    }
171→
172→    return apiRequest<CursorPage<NotificationItem>>(`/getNotifications?${params.toString()}`, {
173→      method: 'GET',
174→      headers: {
175→        ...authHeaders(token),
176→      },
177→    });
178→  },
179→
180→  async getStreak(userId: string): Promise<StreakResponse> {
181→    return apiRequest<StreakResponse>(`/streak/${encodeURIComponent(userId)}`, {
182→      method: 'GET',
183→    });
184→  },
185→
186→  async getUserData(userId: string): Promise<UserDataResponse> {
187→    const params = new URLSearchParams();
188→    params.set('userId', userId);
189→
190→    return apiRequest<UserDataResponse>(`/getUserData?${params.toString()}`, {
191→      method: 'GET',
192→    });
193→  },
194→
195→  async getCanvasGallery(
196→    userId?: string,
197→    limit = 36,
198→    sort: 'hottest' | 'newest' = 'hottest',
199→    cursor?: string | null,
200→  ): Promise<CursorPage<JournalItem>> {
201→    const params = new URLSearchParams();
202→    params.set('limit', String(limit));
203→    params.set('sort', sort);
204→    if (userId) {
205→      params.set('userId', userId);
206→    }
207→    if (cursor) {
208→      params.set('cursor', cursor);
209→    }
210→
211→    return apiRequest<CursorPage<JournalItem>>(`/journals/canvas/gallery?${params.toString()}`, {
212→      method: 'GET',
213→    });
214→  },
215→
216→  async getFreedomWallWeeks(limit = 8, token?: string): Promise<{ data?: FreedomWeek[] }> {
217→    const params = new URLSearchParams();
218→    params.set('limit', String(limit));
219→
220→    return apiRequest<{ data?: FreedomWeek[] }>(`/freedom-wall/weeks?${params.toString()}`, {
221→      method: 'GET',
222→      headers: {
223→        ...authHeaders(token),
224→      },
225→    });
226→  },
227→
228→  async getCurrentFreedomWallWeek(token?: string): Promise<{ data?: FreedomWeek }> {
229→    return apiRequest<{ data?: FreedomWeek }>('/freedom-wall/current', {
230→      method: 'GET',
231→      headers: {
232→        ...authHeaders(token),
233→      },
234→    });
235→  },
236→
237→  async getFreedomWallItems(
238→    weekId: string,
239→    options: { limit?: number; cursor?: string; types?: string[] | string } = {},
240→    token?: string,
241→  ): Promise<CursorPage<FreedomItem>> {
242→    const params = new URLSearchParams();
243→    params.set('limit', String(options.limit ?? 200));
244→    if (options.cursor) {
245→      params.set('cursor', options.cursor);
246→    }
247→    if (Array.isArray(options.types) && options.types.length > 0) {
248→      params.set('types', options.types.join(','));
249→    } else if (typeof options.types === 'string' && options.types.trim().length > 0) {
250→      params.set('types', options.types.trim());
251→    }
252→
253→    return apiRequest<CursorPage<FreedomItem>>(
254→      `/freedom-wall/${encodeURIComponent(weekId)}/items?${params.toString()}`,
255→      {
256→        method: 'GET',
257→        headers: {
258→          ...authHeaders(token),
259→        },
260→      },
261→    );
262→  },
263→
264→  async getUniversePosts(
265→    viewport: { minX: number; maxX: number; minY: number; maxY: number },
266→    limit = 200,
267→  ): Promise<{ data?: UniversePost[] }> {
268→    const params = new URLSearchParams();
269→    params.set('minX', String(viewport.minX));
270→    params.set('maxX', String(viewport.maxX));
271→    params.set('minY', String(viewport.minY));
272→    params.set('maxY', String(viewport.maxY));
273→    params.set('limit', String(limit));
274→
275→    return apiRequest<{ data?: UniversePost[] }>(`/universe/posts?${params.toString()}`, {
276→      method: 'GET',
277→    });
